import Profile2 from './components/Profile2'
import user from './user.json';

export default function App() {
  return (

    <div>

      <Profile2 
          // key={i}
          name={user.name}
          tag={user.tag}
          location={user.location}
          avatar={user.avatar}
          stats={user.stats}
      />

    </div> 
    )}
